mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, S.* FROM ( SELECT s.sugg_no, s.sugg_title, s.sugg_content, s.sugg_writer, s.sugg_pw, s.sugg_answer, s.sugg_cdate, s.sugg_mdate, s.sugg_usage, s.file_origin_name, s.file_save_name, NVL(( SELECT COUNT(*) FROM sugg_comment c WHERE c.comm_sugg_no = s.sugg_no AND c.comm_usage = 'Y' ), 0) AS comment_count FROM suggestion s WHERE s.sugg_usage = 'Y'
AND s.sugg_answer = #{search.sugg_answer}
AND ( UPPER(s.sugg_title) LIKE '%' || UPPER(#{search.keyword}) || '%' OR UPPER(s.sugg_writer) LIKE '%' || UPPER(#{search.keyword}) || '%' )
AND s.sugg_cdate >= TO_DATE(#{search.startDate}, 'YYYY-MM-DD')
AND s.sugg_cdate < TO_DATE(#{search.endDate}, 'YYYY-MM-DD') + 1
ORDER BY s.sugg_cdate desc ) S ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}
